use fastly::http::{header, Method, StatusCode};
use fastly::{Backend, Error, Request, Response};
use std::time::Duration;

const BACKEND_PRIMARY: &str = "primary_backend";
const BACKEND_SECONDARY: &str = "secondary_backend";
const BACKEND_API: &str = "api_backend";

struct BackendConfig {
    name: &'static str,
    host: &'static str,
    port: u16,
    sni_hostname: &'static str,
    use_tls: bool,
    connect_timeout_ms: u64,
    first_byte_timeout_ms: u64,
    between_bytes_timeout_ms: u64,
}

impl BackendConfig {
    fn build_backend(&self) -> Backend {
        let mut builder = Backend::builder(self.name, self.host)
            .override_host(self.host)
            .connect_timeout(Duration::from_millis(self.connect_timeout_ms))
            .first_byte_timeout(Duration::from_millis(self.first_byte_timeout_ms))
            .between_bytes_timeout(Duration::from_millis(self.between_bytes_timeout_ms));

        if self.use_tls {
            builder = builder
                .enable_ssl()
                .ssl_min_version(fastly::experimental::BackendExt::TlsVersion::Tls12)
                .sni_hostname(self.sni_hostname)
                .cert_hostname(self.sni_hostname);
        }

        if self.port != 0 {
            builder = builder.port(self.port);
        }

        builder.finish().expect(&format!("Failed to build backend: {}", self.name))
    }
}

