fn route_request(req: &Request) -> &'static str {
    let path = req.get_path();

    if path.starts_with("/api/") || path.starts_with("/v1/") || path.starts_with("/v2/") {
        BACKEND_API
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.ends_with(".css")
        || path.ends_with(".js")
        || path.ends_with(".png")
        || path.ends_with(".jpg")
        || path.ends_with(".gif")
        || path.ends_with(".svg")
        || path.ends_with(".woff2")
    {
        BACKEND_SECONDARY
    } else {
        BACKEND_PRIMARY
    }
}

fn add_request_headers(req: &mut Request, backend_name: &str) {
    req.set_header("X-Forwarded-Proto", "https");
    req.set_header("X-Backend-Name", backend_name);

    if let Some(client_ip) = req.get_client_ip_addr() {
        req.set_header("X-Forwarded-For", client_ip.to_string());
    }

    req.set_header("X-Request-Id", fastly::handle::RequestHandle::generate_id().unwrap_or_default());
}

fn handle_health_check() -> Response {
    Response::from_status(StatusCode::OK)
        .with_header(header::CONTENT_TYPE, "application/json")
        .with_body(r#"{"status": "healthy", "service": "edge-router"}"#)
}

fn handle_not_allowed() -> Response {
    Response::from_status(StatusCode::METHOD_NOT_ALLOWED)
        .with_header(header::CONTENT_TYPE, "application/json")
        .with_body(r#"{"error": "Method not allowed"}"#)
}

fn handle_error(status: StatusCode, message: &str) -> Response {
    Response::from_status(status)
        .with_header(header::CONTENT_TYPE, "application/json")
        .with_body(format!(r#"{{"error": "{}"}}"#, message))
}

fn process_response(mut resp: Response, backend_name: &str) -> Response {
    resp.set_header("X-Served-By", "fastly-edge-router");
    resp.set_header("X-Backend", backend_name);
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");

    if backend_name == BACKEND_SECONDARY {
        resp.set_header(header::CACHE_CONTROL, "public, max-age=86400, immutable");
    }

    resp
}

fn send_to_backend(mut req: Request, backend_name: &str) -> Result<Response, Error> {
    add_request_headers(&mut req, backend_name);

    match req.send(backend_name) {
        Ok(resp) => Ok(process_response(resp, backend_name)),
        Err(e) => {
            eprintln!("Backend {} error: {:?}", backend_name, e);
            Ok(handle_error(
                StatusCode::BAD_GATEWAY,
                &format!("Backend communication error with {}", backend_name),
            ))
        }
    }
}

fn send_with_failover(mut req: Request, primary: &str, fallback: &str) -> Result<Response, Error> {
    add_request_headers(&mut req, primary);

    let cloned_req = req.clone_with_body();

    match req.send(primary) {
        Ok(resp) => {
            if resp.get_status().is_server_error() {
                eprintln!(
                    "Primary backend {} returned {}, failing over to {}",
                    primary,
                    resp.get_status(),
                    fallback
                );
                send_to_backend(cloned_req, fallback)
            } else {
                Ok(process_response(resp, primary))
            }
        }
        Err(e) => {
            eprintln!(
                "Primary backend {} failed: {:?}, failing over to {}",
                primary, e, fallback
            );
            send_to_backend(cloned_req, fallback)
        }
    }
}

#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    // Initialize backend configurations
    let _configs = get_backend_configs();

    // Handle health check endpoint
    if req.get_path() == "/health" || req.get_path() == "/__health" {
        return Ok(handle_health_check());
    }

    // Reject unsupported methods
    match req.get_method() {
        &Method::GET
        | &Method::HEAD
        | &Method::POST
        | &Method::PUT
        | &Method::PATCH
        | &Method::DELETE
        | &Method::OPTIONS => {}
        _ => return Ok(handle_not_allowed()),
    }

    // Handle CORS preflight
    if req.get_method() == Method::OPTIONS {
        let mut resp = Response::from_status(StatusCode::NO_CONTENT);
        resp.set_header("Access-Control-Allow-Origin", "*");
        resp.set_header(
            "Access-Control-Allow-Methods",
            "GET, HEAD, POST, PUT, PATCH, DELETE, OPTIONS",
        );
        resp.set_header(
            "Access-Control-Allow-Headers",
            "Content-Type, Authorization, X-Requested-With",
        );
        resp.set_header("Access-Control-Max-Age", "86400");
        return Ok(resp);
    }

    // Route the request to the appropriate backend
    let backend_name = route_request(&req);

    // For primary backend, use failover to secondary
    if backend_name == BACKEND_PRIMARY {
        send_with_failover(req, BACKEND_PRIMARY, BACKEND_SECONDARY)
    } else {
        send_to_backend(req, backend_name)
    }
}